mapper.select:
SELECT id, template_id AS templateId, code, name, type, description, base_weight AS baseWeight, direction, scoring_mode AS scoringMode, target_value AS targetValue, unit, target_range AS targetRange, sort_order AS sortOrder, create_time AS createTime, last_modify_time AS lastModifyTime FROM algorithm_core_indicator WHERE template_id IN
#{algorithmTemplateId}
ORDER BY template_id ASC, sort_order ASC, id ASC
